import{_ as e,o as t,c as r,S as i}from"./chunks/framework.DZlzLDBr.js";const p=JSON.parse('{"title":"Charts","description":"","frontmatter":{},"headers":[],"relativePath":"Charts.md","filePath":"Charts.md","lastUpdated":null}'),s={name:"Charts.md"};function o(n,a,l,d,h,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="charts" tabindex="-1">Charts <a class="header-anchor" href="#charts" aria-label="Permalink to &quot;Charts&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Charts in <a href="./Analytics">Analytics</a> help you understand workload, progress, and retention. Use filters first, then interpret chart changes.</p><h2 id="review-calendar-heatmap" tabindex="-1">Review Calendar Heatmap <a class="header-anchor" href="#review-calendar-heatmap" aria-label="Permalink to &quot;Review Calendar Heatmap&quot;">​</a></h2><p>Shows one year of daily review activity.</p><ul><li>darker day = more reviews</li><li>hover for exact date and count</li></ul><p>Use it to spot streaks and missed days.</p><h2 id="stage-distribution" tabindex="-1">Stage Distribution <a class="header-anchor" href="#stage-distribution" aria-label="Permalink to &quot;Stage Distribution&quot;">​</a></h2><p>Shows how cards are split across stages (New, Learning, Review, Relearning, Suspended). More cards in Review usually means the collection is maturing.</p><h2 id="future-due" tabindex="-1">Future Due <a class="header-anchor" href="#future-due" aria-label="Permalink to &quot;Future Due&quot;">​</a></h2><p>Forecast of due cards over the next 30 days. Use it to spot upcoming heavy days before they happen.</p><h2 id="answer-buttons" tabindex="-1">Answer Buttons <a class="header-anchor" href="#answer-buttons" aria-label="Permalink to &quot;Answer Buttons&quot;">​</a></h2><p>30-day stacked view of grade choices (Again/Hard/Good/Easy). Frequent <strong>Again</strong> can signal unclear cards or too much difficulty.</p><h2 id="new-cards-per-day" tabindex="-1">New Cards Per Day <a class="header-anchor" href="#new-cards-per-day" aria-label="Permalink to &quot;New Cards Per Day&quot;">​</a></h2><p>Shows how many new cards were added each day in the last 30 days. Useful for balancing input rate vs review load.</p><h2 id="stability-distribution" tabindex="-1">Stability Distribution <a class="header-anchor" href="#stability-distribution" aria-label="Permalink to &quot;Stability Distribution&quot;">​</a></h2><p>Histogram of stability values:</p><ul><li>low stability = short intervals</li><li>high stability = longer intervals</li></ul><p>Large low-stability clusters can indicate fragile recall.</p><h2 id="forgetting-curve" tabindex="-1">Forgetting Curve <a class="header-anchor" href="#forgetting-curve" aria-label="Permalink to &quot;Forgetting Curve&quot;">​</a></h2><p>Compares your real retention with the FSRS expected curve. If real retention stays below expected, review <a href="./Scheduling">Scheduling</a> settings.</p><h2 id="filter-behavior-and-empty-states" tabindex="-1">Filter behavior and empty states <a class="header-anchor" href="#filter-behavior-and-empty-states" aria-label="Permalink to &quot;Filter behavior and empty states&quot;">​</a></h2><ul><li>Time and scope filters affect every chart.</li><li>Narrow filters can make charts look empty.</li><li>Empty charts usually mean no matching data, not data loss.</li></ul>',24)])])}const b=e(s,[["render",o]]);export{p as __pageData,b as default};
